1	type Cell = [x: number, y: number];
2	type CellKey = string;
3	
4	const toKey = (x: number, y: number): CellKey => `${x},${y}`;
5	
6	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1, 0],           [1, 0],
9	  [-1, 1],  [0, 1],  [1, 1],
10	];
11	
12	const isAliveNextGeneration = (neighborCount: number, isCurrentlyAlive: boolean): boolean =>
13	  neighborCount === 3 || (neighborCount === 2 && isCurrentlyAlive);
14	
15	const countNeighbors = (cells: Cell[]): Map<CellKey, { cell: Cell; count: number }> => {
16	  const counts = new Map<CellKey, { cell: Cell; count: number }>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighbor: Cell = [x + dx, y + dy];
20	      const key = toKey(neighbor[0], neighbor[1]);
21	      const existing = counts.get(key);
22	      counts.set(key, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
23	    }
24	  }
25	  return counts;
26	};
27	
28	export function nextGeneration(cells: Cell[]): Cell[] {
29	  const liveCells = new Set(cells.map(([x, y]) => toKey(x, y)));
30	  const neighborCounts = countNeighbors(cells);
31	  const result: Cell[] = [];
32	  for (const [key, { cell, count }] of neighborCounts) {
33	    if (isAliveNextGeneration(count, liveCells.has(key))) {
34	      result.push(cell);
35	    }
36	  }
37	  return result;
38	}
